        MOD = 10**9 + 7
        z, o, L = zero, one, limit
        if abs(z - o) > L:
            return 0
        dp = [[[0] * 2 for _ in range(o + 1)] for __ in range(z + 1)]
        for i in range(1, z + 1):
            if i <= L:
                dp[i][0][0] = 1
        for j in range(1, o + 1):
            if j <= L:
                dp[0][j][1] = 1
        for i in range(1, z + 1):
            for j in range(1, o + 1):
                dp[i][j][0] = (dp[i - 1][j][0] + dp[i - 1][j][1] - (dp[i - L - 1][j][1] if i - L - 1 >= 0 else 0)) % MOD
                dp[i][j][1] = (dp[i][j - 1][0] + dp[i][j - 1][1] - (dp[i][j - L - 1][0] if j - L - 1 >= 0 else 0)) % MOD
        return (dp[z][o][0] + dp[z][o][1]) % MOD
```
